const items = $input.all();
const collected_at = new Date().toISOString();
const property_id = String($('Webhook').first().json.body.property_id);
const rows = items.map(item => {
  const d = item.json;
  const raw = String(d.date || '');
  const report_date = raw.length === 8 ? raw.slice(0,4)+'-'+raw.slice(4,6)+'-'+raw.slice(6,8) : raw;
  return {
    property_id, report_date,
    sessions: Number(d.sessions) || 0,
    total_users: Number(d.totalUsers) || 0,
    new_users: Number(d.newUsers) || 0,
    screen_page_views: Number(d.screenPageViews) || 0,
    bounce_rate: Number(d.bounceRate) || 0,
    avg_session_duration: Number(d.averageSessionDuration) || 0,
    engagement_rate: Number(d.engagementRate) || 0,
    engaged_sessions: Number(d.engagedSessions) || 0,
    collected_at
  };
}).filter(r => r.property_id && r.report_date);
if (!rows.length) return [{ json: { sql: 'SELECT 1' } }];
const esc = (s) => String(s == null ? '' : s).replace(/'/g, "''").replace(/\$/g, "' || chr(36) || '");
const dedup = new Map();
for (const r of rows) dedup.set(r.property_id + '|' + r.report_date, r);
const values = [...dedup.values()].map(r => "('" + esc(r.property_id) + "','" + esc(r.report_date) + "'::date," + r.sessions + "::integer," + r.total_users + "::integer," + r.new_users + "::integer," + r.screen_page_views + "::integer," + r.bounce_rate + "::numeric," + r.avg_session_duration + "::numeric," + r.engagement_rate + "::numeric," + r.engaged_sessions + "::integer,'" + esc(r.collected_at) + "'::timestamptz)").join(',');
const sql = "INSERT INTO ga_daily_overview (property_id,report_date,sessions,total_users,new_users,screen_page_views,bounce_rate,avg_session_duration,engagement_rate,engaged_sessions,collected_at) VALUES " + values + " ON CONFLICT (property_id,report_date) DO UPDATE SET sessions=EXCLUDED.sessions,total_users=EXCLUDED.total_users,new_users=EXCLUDED.new_users,screen_page_views=EXCLUDED.screen_page_views,bounce_rate=EXCLUDED.bounce_rate,avg_session_duration=EXCLUDED.avg_session_duration,engagement_rate=EXCLUDED.engagement_rate,engaged_sessions=EXCLUDED.engaged_sessions,collected_at=EXCLUDED.collected_at";
return [{ json: { sql } }];

